"use client";

import { useParams } from "next/navigation";
import { useCallback, useEffect, useState } from "react";
import { ExternalLink } from "lucide-react";
import { ApplicantForm } from "@/components/applicants/applicant-form";
import { ApplicantStatusBadge } from "@/components/applicants/applicant-status-badge";
import { Button } from "@/components/ui/button";
import { Select } from "@/components/ui/select";
import { apiFetch } from "@/lib/api";
import type { Applicant, ApplicantStatus } from "@/lib/types";

const statuses: ApplicantStatus[] = ["Applied", "Screening", "Interview", "Offered", "Hired", "Rejected"];

export default function ApplicantDetailPage() {
  const params = useParams<{ id: string }>();
  const [applicant, setApplicant] = useState<Applicant | null>(null);
  const [status, setStatus] = useState<ApplicantStatus>("Applied");
  const [message, setMessage] = useState("");
  const [busy, setBusy] = useState(false);

  const loadApplicant = useCallback(async () => {
    const response = await apiFetch<{ data: Applicant }>(`/api/applicant/${params.id}`);
    setApplicant(response.data);
    setStatus(response.data.status);
  }, [params.id]);

  useEffect(() => {
    loadApplicant();
  }, [loadApplicant]);

  async function updateStatus() {
    if (!applicant) return;
    setBusy(true);
    setMessage("");
    try {
      await apiFetch(`/api/applicant/${applicant.id}`, {
        method: "PUT",
        body: JSON.stringify({ status })
      });
      setMessage("Pipeline stage updated.");
      await loadApplicant();
    } catch (err) {
      setMessage(err instanceof Error ? err.message : "Unable to update stage");
    } finally {
      setBusy(false);
    }
  }

  if (!applicant) {
    return <div className="text-sm text-muted-foreground">Loading applicant...</div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 md:flex-row md:items-end md:justify-between">
        <div>
          <p className="text-sm uppercase text-muted-foreground">Applicant profile</p>
          <h1 className="text-3xl font-semibold">{applicant.name}</h1>
          <p className="text-sm text-muted-foreground">{applicant.position}</p>
        </div>
        <ApplicantStatusBadge status={applicant.status} />
      </div>

      <div className="grid gap-4 lg:grid-cols-[1fr_360px]">
        <section className="rounded-lg border border-border bg-background p-5 shadow-soft">
          <h2 className="mb-4 text-base font-semibold">Applicant Details</h2>
          <div className="grid gap-3 md:grid-cols-2">
            <Info label="Email" value={applicant.email} />
            <Info label="Phone" value={applicant.phone} />
            <Info label="Department" value={applicant.department} />
            <Info label="Experience" value={applicant.experience} />
            <Info label="Source" value={applicant.source} />
            <Info label="Recruiter / Owner" value={applicant.owner} />
            <Info
              label="Expected Joining Date"
              value={applicant.expected_joining_date ? new Date(applicant.expected_joining_date).toLocaleDateString() : "Not set"}
            />
            <Info label="Created" value={new Date(applicant.created_at).toLocaleString()} />
          </div>
          {applicant.resume_url ? (
            <a
              className="mt-4 inline-flex h-10 items-center justify-center rounded-lg border border-border bg-background px-4 text-sm font-medium hover:bg-muted"
              href={applicant.resume_url}
              target="_blank"
              rel="noreferrer"
            >
              <ExternalLink className="mr-2 h-4 w-4" />
              Open Resume
            </a>
          ) : null}
        </section>

        <section className="rounded-lg border border-border bg-background p-5 shadow-soft">
          <h2 className="mb-4 text-base font-semibold">Pipeline Stage</h2>
          <div className="space-y-3">
            <Select value={status} onChange={(event) => setStatus(event.target.value as ApplicantStatus)}>
              {statuses.map((item) => (
                <option key={item} value={item}>
                  {item}
                </option>
              ))}
            </Select>
            <Button className="w-full" onClick={updateStatus} disabled={busy}>
              {busy ? "Updating..." : "Update Stage"}
            </Button>
          </div>
          {message ? <p className="mt-3 text-sm text-muted-foreground">{message}</p> : null}
        </section>
      </div>

      {applicant.notes ? (
        <section className="rounded-lg border border-border bg-background p-5 shadow-soft">
          <h2 className="mb-2 text-base font-semibold">Notes</h2>
          <p className="whitespace-pre-wrap text-sm text-muted-foreground">{applicant.notes}</p>
        </section>
      ) : null}

      <section>
        <h2 className="mb-3 text-base font-semibold">Edit Applicant</h2>
        <ApplicantForm initial={applicant} />
      </section>
    </div>
  );
}

function Info({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <p className="text-xs uppercase text-muted-foreground">{label}</p>
      <p className="text-sm font-medium">{value}</p>
    </div>
  );
}
